sp_widget.client_script:
api.controller = function() {
  var c = this;

  c.submitting = false;

  c.form = {
    consumer_name: '',
    consumer_email: '',
    consumer_phone: '',
    device_type: '',
    device_model: '',
    device_condition: '',
    postal_address: '',
    agreement: false
  };

  c.errors = {};

  c.validate = function() {
    c.errors = {};
    if (!c.form.consumer_name) c.errors.consumer_name = 'Full name is required.';
    if (!c.form.consumer_email) {
      c.errors.consumer_email = 'Email address is required.';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(c.form.consumer_email)) {
      c.errors.consumer_email = 'Please enter a valid email address.';
    }
    if (!c.form.device_type) c.errors.device_type = 'Please select a device type.';
    if (!c.form.device_model) c.errors.device_model = 'Device model is required.';
    if (!c.form.device_condition) c.errors.device_condition = 'Please select the device condition.';
    if (!c.form.postal_address) c.errors.postal_address = 'Postal address is required.';
    if (!c.form.agreement) c.errors.agreement = 'You must confirm the data backup agreement.';
    return Object.keys(c.errors).length === 0;
  };

  c.submit = function() {
    if (!c.validate()) return;
    c.submitting = true;
    c.server.get({
      action: 'submit',
      consumer_name: c.form.consumer_name,
      consumer_email: c.form.consumer_email,
      consumer_phone: c.form.consumer_phone,
      device_type: c.form.device_type,
      device_model: c.form.device_model,
      device_condition: c.form.device_condition,
      postal_address: c.form.postal_address
    }).then(function(r) {
      c.data = r.data;
      c.submitting = false;
    }, function() {
      c.submitting = false;
      c.data.submitted = true;
      c.data.success = false;
      c.data.message = 'A network error occurred. Please try again.';
    });
  };

  c.hasError = function(field) {
    return c.errors[field] ? true : false;
  };
};

sp_widget.css:
/* Page header within widget */
.cb-page-header {
  margin-bottom: 32px;
}
.cb-page-title {
  font-size: 26px;
  font-weight: 700;
  color: $text-color;
  margin: 0 0 8px;
}
.cb-title-icon {
  color: $brand-primary;
  margin-right: 8px;
  font-size: 26px;
}
.cb-page-subtitle {
  font-size: $font-size-base;
  max-width: 480px;
  margin: 0 auto;
}

/* Form input styling */
.sp-input {
  height: $input-height-base;
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-base;
  padding: 0 12px;
  font-size: $font-size-base;
  color: $text-color;
  background: $background-primary;
  transition: border-color 0.15s, box-shadow 0.15s;
  width: 100%;
  &:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
    outline: none;
  }
}
.has-error .sp-input,
.has-error .sp-select,
.has-error .sp-textarea {
  border-color: $brand-danger;
}

/* Select / dropdown */
.sp-select-wrapper {
  position: relative;
}
.sp-select {
  appearance: none;
  -webkit-appearance: none;
  padding-right: 36px;
  height: $input-height-base;
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-base;
  cursor: pointer;
  color: $text-color;
  background: $background-primary;
  &:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
    outline: none;
  }
}
.sp-select-chevron {
  position: absolute;
  right: 12px;
  top: 50%;
  transform: translateY(-50%);
  color: $text-muted;
  pointer-events: none;
  font-size: 12px;
}

/* Textarea */
.sp-textarea {
  border-radius: $border-radius-base;
  border: 1px solid $border-tertiary;
  padding: 12px;
  font-size: $font-size-base;
  color: $text-color;
  background: $background-primary;
  resize: vertical;
  min-height: 100px;
  transition: border-color 0.15s;
  &:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
    outline: none;
  }
}

/* Primary button */
.sp-btn-primary {
  height: 44px;
  padding: 0 24px;
  border-radius: $border-radius-base;
  font-size: $font-size-base;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  transition: background 0.15s, box-shadow 0.15s;
  cursor: pointer;
  border: none;
  background: $brand-primary;
  color: $btn-primary-color;
  &:hover:not(:disabled) {
    background: $brand-primary-dark;
    box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
    color: $btn-primary-color;
  }
  &:disabled {
    opacity: 0.55;
    cursor: not-allowed;
  }
}

/* Agreement checkbox */
.cb-agreement label {
  font-size: $font-size-base;
  color: $text-color;
  font-weight: 400;
}

/* Submit row */
.cb-submit-row {
  margin-top: 24px;
  padding-top: 24px;
  border-top: 1px solid $border-tertiary;
}
.cb-submit-btn {
  width: 100%;
  justify-content: center;
}

/* Confirmation screen */
.cb-confirmation {
  padding: 48px 24px;
}
.cb-success-icon {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  background: $brand-primary;
  color: $btn-primary-color;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 32px;
  margin-bottom: 24px;
}
.cb-confirm-title {
  font-size: 26px;
  font-weight: 700;
  color: $text-color;
  margin: 0 0 8px;
}
.cb-confirm-ref {
  font-size: $font-size-base;
  color: $text-muted;
  margin-bottom: 8px;
}
.cb-ref-badge {
  display: inline-block;
  background: $background-secondary;
  border: 2px solid $brand-primary;
  border-radius: $border-radius-large;
  padding: 12px 32px;
  font-size: 22px;
  font-weight: 700;
  color: $brand-primary;
  letter-spacing: 0.05em;
  margin-bottom: 24px;
}
.cb-confirm-msg {
  max-width: 480px;
  margin: 0 auto;
  line-height: 1.6;
}

/* Spinner */
@keyframes sp-spin {
  to { transform: rotate(360deg); }
}
.sp-spin {
  animation: sp-spin 0.8s linear infinite;
}

sp_widget.script:
(function() {
  data.submitted = false;
  data.success = false;
  data.message = '';
  data.returnRef = '';

  data.deviceTypes = [
    { value: 'smartphone', label: 'Smartphone' },
    { value: 'tablet', label: 'Tablet' },
    { value: 'laptop', label: 'Laptop' },
    { value: 'headphones', label: 'Headphones' },
    { value: 'other', label: 'Other' }
  ];

  data.conditions = [
    { value: 'working', label: 'Working - powers on normally' },
    { value: 'minor_damage', label: 'Minor Damage - some wear but functional' },
    { value: 'major_damage', label: 'Major Damage - does not power on' },
    { value: 'unknown', label: 'Unknown' }
  ];

  if (input && input.action === 'submit') {
    try {
      var gr = new GlideRecord('x_1845356_circle_0_return_request');
      gr.initialize();
      gr.setValue('consumer_name', input.consumer_name);
      gr.setValue('consumer_email', input.consumer_email);
      if (input.consumer_phone) {
        gr.setValue('consumer_phone', input.consumer_phone);
      }
      gr.setValue('device_type', input.device_type);
      gr.setValue('device_model', input.device_model);
      gr.setValue('device_condition', input.device_condition);
      gr.setValue('postal_address', input.postal_address);
      gr.setValue('status', 'submitted');

      var sysId = gr.insert();

      if (sysId) {
        gr.get(sysId);
        data.submitted = true;
        data.success = true;
        data.returnRef = gr.getValue('return_reference');
        data.message = 'Your return request has been submitted successfully.';
      } else {
        data.submitted = true;
        data.success = false;
        data.message = 'We could not process your request. Please try again.';
      }
    } catch (e) {
      gs.error('CircleBack return form error: ' + e.message);
      data.submitted = true;
      data.success = false;
      data.message = 'An unexpected error occurred. Please try again later.';
    }
    return;
  }
})();
